// Helper function to get detail content by slug
export function getDetailContent(slug: string): string | undefined {
  const detail = DETAIL_CONTENT.find(d => d.slug === slug);
  return detail?.content;
}

// Helper function to get detail by category
export function getDetailsByCategory(category: 'Exhibition' | 'Moving Image Program' | 'Residency'): DetailContent[] {
  return DETAIL_CONTENT.filter(d => d.category === category);
}

// Helper function to get detail content by slug and language
export function getDetailContentByLanguage(slug: string, language: 'en' | 'th'): string | undefined {
  if (language === 'th') {
    return getDetailContentThai(slug);
  }
  return getDetailContent(slug);
}
